import React from "react";
import {
  Flex,
  Box,
  Input,
  Button,
  IconButton,
  useBreakpointValue,
  Text,
  useDisclosure,
  InputGroup,
  InputLeftElement,
} from "@chakra-ui/react";
import { FaSearch, FaBars } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import { NavBarDrawer } from "../components/NavBarDrawer";

const Navbar = () => {
  const isMobile = useBreakpointValue({ base: true, lg: false });
  const { isOpen, onOpen, onClose } = useDisclosure();
  const navigate = useNavigate();

  return (
    <Box>
      <Flex
        as="nav"
        align="center"
        justify="space-between"
        px={6}
        py={3}
         top="0" 
        bg="white"
        boxShadow="sm"
        position="fixed"
        width="100%"
        zIndex={100}
      >
        {/* LEFT */}
        <Flex align="center" gap={6}>
          {/* Logo */}
          <Text
            fontSize="2xl"
            fontWeight="bold"
            color="#A435F0"
            cursor="pointer"
            onClick={() => navigate("/")}
          >
            SRM
          </Text>

          {/* Explore (Desktop only) */}
          {!isMobile && (
            <Text
              fontSize="sm"
              cursor="pointer"
              _hover={{ color: "#A435F0" }}
            >
              Explore
            </Text>
          )}
        </Flex>

        {/* SEARCH */}
        {!isMobile && (
          <Box flex="1" mx={10}>
            <InputGroup>
              <InputLeftElement pointerEvents="none">
                <FaSearch color="gray" />
              </InputLeftElement>

              <Input
                placeholder="Search for anything"
                borderRadius="999px"
                bg="#f7f9fa"
                _focus={{
                  bg: "white",
                  borderColor: "#A435F0",
                }}
              />
            </InputGroup>
          </Box>
        )}

        {/* RIGHT */}
        {!isMobile ? (
          <Flex align="center" gap={4}>
            <Button
              variant="ghost"
              onClick={() => navigate("/login")}
            >
              Log in
            </Button>

            <Button
              border="1px solid black"
              bg="white"
              _hover={{ bg: "gray.100" }}
              onClick={() => navigate("/signup")}
            >
              Sign up
            </Button>
          </Flex>
        ) : (
          <Flex align="center">
            <IconButton
              icon={<FaBars />}
              variant="ghost"
              onClick={onOpen}
            />
          </Flex>
        )}
      </Flex>

      {/* Drawer Mobile */}
      <NavBarDrawer
        isOpen={isOpen}
        onOpen={onOpen}
        onClose={onClose}
      />
    </Box>
  );
};

export default Navbar;
